import React from "react";
import { BrowserRouter as Router, Routes, Route, Link } from "react-router-dom";
import AuctionList from "./pages/AuctionList";
import CreateRFQ from "./pages/CreateRFQ";
import AuctionDetail from "./pages/AuctionDetail";

const Navbar = () => {
  return (
    <nav className="w-full h-16 bg-[#1e3a5f] text-white px-4 sm:px-8 flex items-center justify-between shadow-lg">
      <Link to="/" className="font-bold text-base sm:text-lg tracking-wide">
        British Auction - RFQ System
      </Link>
      <div className="flex items-center gap-2 sm:gap-3">
        <Link
          to="/"
          className="px-3 py-2 rounded-md text-sm font-medium hover:bg-white/10 transition"
        >
          All Auctions
        </Link>
        <Link
          to="/create-rfq"
          className="px-3 py-2 rounded-md text-sm font-medium bg-[#2563eb] hover:bg-blue-700 transition"
        >
          Create RFQ
        </Link>
      </div>
    </nav>
  );
};

const App = () => {
  return (
    <Router>
      <Navbar />
      <div className="min-h-[calc(100vh-4rem)] bg-[#f1f5f9]">
        <Routes>
          <Route path="/" element={<AuctionList />} />
          <Route path="/create-rfq" element={<CreateRFQ />} />
          <Route path="/rfq/:id" element={<AuctionDetail />} />
        </Routes>
      </div>
    </Router>
  );
};

export default App;
